INSERT INTO repo_snapshots VALUES (nextval('seq_repo_snapshots'), 1, 'AustinCStone', 'social', 41383029, 'Founderati-client', 'AustinCStone/Founderati-client', 'AngelList or LinkedIn, are excellent tools, but these networks are so large that it returns to a game of “who you know” offline.  It is easy to get lost in the crowd.  Founders and investors alike need a better means of discovering and connecting with each other, and they need this to be filtered so that the bozos and spammers stay out.  They need a way to meet strangers for shared benefit.  There is no better filter than affinity, and this is the premise of Founderati.  Founderati is a network for entrepreneurs, investors and startup builders that is limited to a given university alumni community.  There are few icebreakers as strong as attending the same college.  To further ensure the quality of the network, Founderati comprised only of invited individuals who must then complete an application that is reviewed for approval or rejection by an admin.  Simply put, startup-minded Founderati enables students and alumni to connect with each other without having to filter through spammers and goofballs.  Only the best of a given alumni are admitted.', 'JavaScript', 0, 1, '2015-08-25T19:16:57Z', 'https://github.com/AustinCStone/Founderati-client', 0, '#d3869b', 'ERGODIC', TIMESTAMP '2026-03-31 21:35:34');
