-- World Increment DuckLake Setup
-- Generated: 2026-03-31T21:35:34Z

CREATE SEQUENCE IF NOT EXISTS seq_world_increments START 1;
CREATE SEQUENCE IF NOT EXISTS seq_repo_snapshots START 1;
CREATE SEQUENCE IF NOT EXISTS seq_aptos_snapshots START 1;
CREATE SEQUENCE IF NOT EXISTS seq_multisig_probes START 1;
CREATE SEQUENCE IF NOT EXISTS seq_mnx_snapshots START 1;

CREATE TABLE IF NOT EXISTS world_increments (
    id INTEGER PRIMARY KEY,
    sweep_ts TIMESTAMP,
    description VARCHAR,
    gf3_trit INTEGER,
    gf3_color VARCHAR,
    gf3_label VARCHAR
);
CREATE TABLE IF NOT EXISTS repo_snapshots (
    id INTEGER PRIMARY KEY,
    world_increment_id INTEGER,
    source_org VARCHAR,
    source_type VARCHAR,
    repo_id BIGINT,
    repo_name VARCHAR,
    full_name VARCHAR,
    description VARCHAR,
    language VARCHAR,
    stars INTEGER,
    forks INTEGER,
    pushed_at VARCHAR,
    html_url VARCHAR,
    gf3_trit INTEGER,
    gf3_color VARCHAR,
    gf3_label VARCHAR,
    snapshot_ts TIMESTAMP
);
CREATE TABLE IF NOT EXISTS aptos_snapshots (
    id INTEGER PRIMARY KEY,
    world_increment_id INTEGER,
    label VARCHAR,
    address VARCHAR,
    raw_balance VARCHAR,
    apt_balance DOUBLE,
    gf3_trit INTEGER,
    gf3_color VARCHAR,
    gf3_label VARCHAR,
    snapshot_ts TIMESTAMP
);
CREATE TABLE IF NOT EXISTS multisig_probes (
    id INTEGER PRIMARY KEY,
    world_increment_id INTEGER,
    pair_label VARCHAR,
    address VARCHAR,
    signatures_required VARCHAR,
    snapshot_ts TIMESTAMP
);
CREATE TABLE IF NOT EXISTS mnx_snapshots (
    id INTEGER PRIMARY KEY,
    world_increment_id INTEGER,
    endpoint VARCHAR,
    status VARCHAR,
    raw_data VARCHAR,
    snapshot_ts TIMESTAMP
);





